class Shape:
    def area(self):
        return 0

class Square(Shape):
    def __init__(self, side):
        self.side = side

    def area(self):
        return self.side ** 2

class Rectangle(Square):
    def __init__(self, length, breadth):
        super().__init__(length)
        self.breadth = breadth

    # area is intentionally missing here

# Test cases
def test_shapes():
    s = Square(4)
    assert s.area() == 16, f"Expected 16 but got {s.area()}"

    r = Rectangle(5, 4)
    assert r.area() == 20, f"Expected 20 but got {r.area()}"

    print("All tests passed.")

